class Solution {
public:
    int __attribute__((unused)) flipBitToZero(int n) {
        int counter = 0;
        int xored = n;
        for (int i = 0; i < 32; i++) {
            if ((n & (1 << i)) != 0) {
                counter++; // Counting set bits
                xored ^= (1 << i); // Flip the current bit
            }
        }
        return counter;
    }
};

